mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, T.* FROM ( SELECT JP.job_id AS jobId, JP.fk_memberid AS memberId, JP.title AS title, JP.work_type AS workType, JP.career_type AS careerType, JP.fk_edu_code AS educationLevel, JP.salary AS salary, JP.headcount AS headcount, JP.status AS status, JP.deadline_type AS deadlineType, TO_CHAR(JP.deadline_at, 'YYYY.MM.DD') AS deadlineAt, JP.view_count AS viewCount, TO_CHAR(JP.created_at, 'YYYY.MM.DD') AS createdAt, C.company_name AS companyName, JC.category_name AS categoryName, R.region_name AS regionName, PR.region_name AS parentRegionName, CI.company_type AS companyType, (SELECT LISTAGG(S.skill_name, ',') WITHIN GROUP (ORDER BY S.skill_name) FROM tbl_job_posting_skill JPS JOIN tbl_skill S ON JPS.fk_skill_id = S.skill_id WHERE JPS.fk_job_id = JP.job_id) AS skillNames, (SELECT COUNT(*) FROM tbl_job_scrap SC WHERE SC.fk_job_id = JP.job_id) AS scrapCount, CASE WHEN JP.deadline_type = 'always' THEN '상시채용' WHEN JP.status = '마감' THEN '마감' WHEN JP.deadline_at < TRUNC(SYSDATE) THEN '마감' WHEN TRUNC(JP.deadline_at) = TRUNC(SYSDATE) THEN 'D-Day' ELSE 'D-' || (TRUNC(JP.deadline_at) - TRUNC(SYSDATE)) END AS dDay, CASE WHEN JP.deadline_type = 'always' THEN 'N' WHEN JP.status = '마감' THEN 'N' WHEN TRUNC(JP.deadline_at) < TRUNC(SYSDATE) THEN 'N' WHEN (TRUNC(JP.deadline_at) - TRUNC(SYSDATE)) <= 7 THEN 'Y' ELSE 'N' END AS dDayUrgent FROM tbl_job_posting JP JOIN tbl_company C ON JP.fk_memberid = C.fk_memberid JOIN tbl_region R ON JP.fk_region_code = R.region_code LEFT JOIN tbl_region PR ON R.fk_parent_region_code = PR.region_code JOIN tbl_job_category JC ON JP.fk_category_id = JC.category_id LEFT JOIN tbl_company_intro CI ON C.fk_memberid = CI.fk_memberid WHERE 1=1
ORDER BY CASE WHEN JP.deadline_type = 'always' THEN 1 ELSE 0 END, JP.deadline_at ASC
ORDER BY JP.view_count DESC, JP.created_at DESC
ORDER BY JP.created_at DESC, JP.job_id DESC
) T WHERE ROWNUM <= #{endRow} ) WHERE rnum >= #{startRow}

