mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, T.* FROM ( SELECT JP.job_id AS "id", JP.title AS "title", C.company_name AS "companyName", R.region_name AS "region", PR.region_name AS "parentRegion", JC.category_name AS "categoryName", JP.career_type AS "career", JP.work_type AS "workType", JP.salary AS "salaryNum", JP.view_count AS "viewCount", EL.edu_level_name AS "eduLevelName", CASE WHEN JP.deadline_type = 'always' THEN '상시채용' ELSE TO_CHAR(JP.deadline_at, 'YYYY.MM.DD') END AS "deadline", CASE WHEN JP.deadline_type = 'always' THEN '상시' WHEN JP.status = '마감' THEN '마감' WHEN JP.deadline_at < TRUNC(SYSDATE) THEN '마감' WHEN TRUNC(JP.deadline_at) = TRUNC(SYSDATE) THEN 'D-Day' ELSE 'D-' || TRUNC(TRUNC(JP.deadline_at) - TRUNC(SYSDATE)) END AS "dday", CASE WHEN JP.status = '마감' THEN 1 WHEN JP.deadline_type != 'always' AND JP.deadline_at < TRUNC(SYSDATE) THEN 1 ELSE 0 END AS "closed", CASE WHEN EXISTS ( SELECT 1 FROM tbl_job_application JA WHERE JA.fk_job_id = JP.job_id AND JA.fk_memberid = #{memberId} AND JA.application_status = 0 ) THEN 1 ELSE 0 END AS "applied", CASE WHEN JP.status = '삭제됨' THEN 1 ELSE 0 END AS "deleted", CASE WHEN JP.is_hidden = 1 THEN 1 ELSE 0 END AS "hidden", TO_CHAR(SC.scrapped_at, 'YYYY.MM.DD') AS "scrappedAt", (SELECT LISTAGG(S.skill_name, ',') WITHIN GROUP (ORDER BY S.skill_name) FROM tbl_job_posting_skill JPS JOIN tbl_skill S ON JPS.fk_skill_id = S.skill_id WHERE JPS.fk_job_id = JP.job_id) AS "skillNames" FROM tbl_job_scrap SC JOIN tbl_job_posting JP ON SC.fk_job_id = JP.job_id JOIN tbl_company C ON JP.fk_memberid = C.fk_memberid JOIN tbl_region R ON JP.fk_region_code = R.region_code LEFT JOIN tbl_region PR ON R.fk_parent_region_code = PR.region_code JOIN tbl_job_category JC ON JP.fk_category_id = JC.category_id LEFT JOIN tbl_education_level EL ON JP.fk_edu_code = EL.edu_level_code WHERE SC.fk_memberid = #{memberId}
AND ( UPPER(JP.title) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(C.company_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(JC.category_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(JP.content) LIKE '%' || UPPER(#{keyword}) || '%' OR EXISTS ( SELECT 1 FROM tbl_job_posting_skill JPS2 JOIN tbl_skill S2 ON JPS2.fk_skill_id = S2.skill_id WHERE JPS2.fk_job_id = JP.job_id AND UPPER(S2.skill_name) LIKE '%' || UPPER(#{keyword}) || '%' ) )
ORDER BY CASE WHEN JP.deadline_type = 'always' THEN 1 ELSE 0 END, JP.deadline_at ASC
ORDER BY SC.scrapped_at DESC
) T WHERE ROWNUM <= #{endRow} ) WHERE rnum >= #{startRow}

SELECT * FROM ( SELECT ROWNUM AS rnum, T.* FROM ( SELECT JP.job_id AS "id", JP.title AS "title", C.company_name AS "companyName", R.region_name AS "region", JC.category_name AS "role", JP.career_type AS "career", JP.work_type AS "empType", CASE WHEN JP.salary IS NOT NULL THEN TO_CHAR(JP.salary, 'FM999,999') || '만원' ELSE '협의' END AS "salaryText", CASE WHEN JP.deadline_type = 'always' THEN '상시채용' ELSE TO_CHAR(JP.deadline_at, 'YYYY.MM.DD') END AS "deadline", CASE WHEN JP.status = '마감' THEN 1 WHEN JP.deadline_type != 'always' AND JP.deadline_at < TRUNC(SYSDATE) THEN 1 ELSE 0 END AS "closed", CASE WHEN EXISTS ( SELECT 1 FROM tbl_job_scrap SC2 WHERE SC2.fk_job_id = JP.job_id AND SC2.fk_memberid = #{memberId} ) THEN 1 ELSE 0 END AS "scrapped", JP.view_count AS "viewCnt", CASE WHEN JP.created_at >= SYSDATE - 7 THEN 1 ELSE 0 END AS "isNew", TO_CHAR(VP.viewed_at, 'YYYY.MM.DD') AS "viewedDate", CASE WHEN TRUNC(SYSDATE) = TRUNC(VP.viewed_at) AND FLOOR((SYSDATE - VP.viewed_at) * 24) < 1 THEN CASE WHEN FLOOR((SYSDATE - VP.viewed_at) * 24 * 60) < 1 THEN '방금 전' ELSE FLOOR((SYSDATE - VP.viewed_at) * 24 * 60) || '분 전' END WHEN TRUNC(SYSDATE) = TRUNC(VP.viewed_at) THEN FLOOR((SYSDATE - VP.viewed_at) * 24) || '시간 전' WHEN TRUNC(SYSDATE) - TRUNC(VP.viewed_at) = 1 THEN '1일 전' ELSE FLOOR(TRUNC(SYSDATE) - TRUNC(VP.viewed_at)) || '일 전' END AS "viewedAt", (SELECT LISTAGG(S.skill_name, ',') WITHIN GROUP (ORDER BY S.skill_name) FROM tbl_job_posting_skill JPS JOIN tbl_skill S ON JPS.fk_skill_id = S.skill_id WHERE JPS.fk_job_id = JP.job_id) AS "skillNames", CASE WHEN JP.status = '삭제됨' THEN 1 ELSE 0 END AS "deleted", CASE WHEN JP.is_hidden = 1 THEN 1 ELSE 0 END AS "hidden", EL.edu_level_name AS "eduLevelName" FROM tbl_viewed_posting VP JOIN tbl_job_posting JP ON VP.fk_job_id = JP.job_id JOIN tbl_company C ON JP.fk_memberid = C.fk_memberid JOIN tbl_region R ON JP.fk_region_code = R.region_code JOIN tbl_job_category JC ON JP.fk_category_id = JC.category_id LEFT JOIN tbl_education_level EL ON JP.fk_edu_code = EL.edu_level_code WHERE VP.fk_memberid = #{memberId}
AND ( UPPER(JP.title) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(C.company_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(JC.category_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(JP.content) LIKE '%' || UPPER(#{keyword}) || '%' OR EXISTS ( SELECT 1 FROM tbl_job_posting_skill JPS2 JOIN tbl_skill S2 ON JPS2.fk_skill_id = S2.skill_id WHERE JPS2.fk_job_id = JP.job_id AND UPPER(S2.skill_name) LIKE '%' || UPPER(#{keyword}) || '%' ) )
AND VP.viewed_at >= TRUNC(SYSDATE) - #{period} + 1
AND VP.viewed_at >= TO_DATE(#{dateFrom}, 'YYYY-MM-DD')
AND VP.viewed_at < TO_DATE(#{dateTo}, 'YYYY-MM-DD') + 1
ORDER BY VP.viewed_at DESC ) T WHERE ROWNUM <= #{endRow} ) WHERE rnum >= #{startRow}

mapper.delete:
DELETE FROM tbl_viewed_posting
WHERE fk_job_id = #{jobId}
  AND fk_memberid = #{memberId}
